query:
-- Orphaned clients (clients without valid userId)
SELECT COUNT(*) as orphaned_clients FROM clients c WHERE c.userId NOT IN (SELECT id FROM users);

-- Orphaned invoices (invoices without valid userId or contractId)
SELECT COUNT(*) as orphaned_invoices_no_user FROM invoices i WHERE i.userId NOT IN (SELECT id FROM users);
SELECT COUNT(*) as orphaned_invoices_no_contract FROM invoices i WHERE i.contractId NOT IN (SELECT id FROM rentalContracts);

-- Orphaned rental contracts (contracts without valid userId or vehicleId)
SELECT COUNT(*) as orphaned_contracts_no_user FROM rentalContracts rc WHERE rc.userId NOT IN (SELECT id FROM users);
SELECT COUNT(*) as orphaned_contracts_no_vehicle FROM rentalContracts rc WHERE rc.vehicleId NOT IN (SELECT id FROM vehicles);

-- Orphaned maintenance records
SELECT COUNT(*) as orphaned_maintenance_no_user FROM maintenanceRecords mr WHERE mr.userId NOT IN (SELECT id FROM users);
SELECT COUNT(*) as orphaned_maintenance_no_vehicle FROM maintenanceRecords mr WHERE mr.vehicleId NOT IN (SELECT id FROM vehicles);

-- Orphaned damage marks
SELECT COUNT(*) as orphaned_damage_no_user FROM damageMarks dm WHERE dm.userId NOT IN (SELECT id FROM users);
SELECT COUNT(*) as orphaned_damage_no_contract FROM damageMarks dm WHERE dm.contractId NOT IN (SELECT id FROM rentalContracts);

-- Check totals
SELECT 'clients' as table_name, COUNT(*) as total_records FROM clients
UNION ALL
SELECT 'invoices', COUNT(*) FROM invoices
UNION ALL
SELECT 'rentalContracts', COUNT(*) FROM rentalContracts
UNION ALL
SELECT 'maintenanceRecords', COUNT(*) FROM maintenanceRecords
UNION ALL
SELECT 'damageMarks', COUNT(*) FROM damageMarks;

